mapper.select:
SELECT /* @SQLID=SUB0206_04-01#Sql001 */ * FROM ( SELECT count(*) over() as totalRow , DATE_YMD AS DATE_YMD , BROKER_CODE AS BROKER_CODE , BROKER_NAME AS BROKER_NAME , DEALER_NUMBER AS DEALER_NUMBER , BROKER_BRANCH_CODE AS BROKER_BRANCH_CODE , BROKER_CHARGE_CODE AS EMP_CODE , BROKER_CHARGE_NAME AS BROKER_CHARGE_NAME , CUSTOMER_ATTRIBUTE AS CUSTOMER_ATTRIBUTE , CUSTOMER_ATTRIBUTE_NAME AS COURCE_NAME , BUTEN_CODE AS BUTEN , ACCOUNT_NUMBER AS ACCOUNT_NUMBER , NAME_KANJI AS CUSTOMER_NAME_KANJI , NAME_KANA AS CUSTOMER_NAME_KANA , JOINT_BRANCH_CODE AS JOINT_BRANCH_CODE , JOINT_BRANCH_NAME AS JOINT_BRANCH_NAME , PRODUT_CD AS PRODUT_CD , PRODUT_NAME AS SECURIYT_CLASS , BRAND_CODE AS BRAND_CODE_CURRENCY , BRAND_NAME AS BRAND_NAME , TRADE_CD AS TRADE_CD , TRADE_NAME AS TRADE_TYPE_NAME , BALANCE_TYPE AS BALANCE_TYPE , DEPOSIT_NAME AS DEPOSIT_NAME , DEPOSIT_TYPE AS DEPOSIT_TYPE , COUNTRY_CODE AS COUNTRY_CODE
, ACQUIRE_PRICE AS ACQUIRE_PRICE , APPRAISE_MARKET_PRICE AS APPRAISE_MARKET_PRICE , APPRAISE_PROFIT_LOSS_PRICE AS APPRAISE_PROFIT_LOSS_PRICE , EXEC_BASE_BALANCE AS CONTRACT_STANDARD_DEPOSIT , CURRENCT_PRICE AS CURRENT_PRICE , CURRENCY AS CURRENCY , FOREIGN_CURRENCT_PRICE AS FOREIGN_VALUATION , EXCHANGE_RATE AS FX_RATE , CASE DISPLAY_LAST_TRADE_DATE WHEN '99991231' THEN '----/--/--' ELSE TO_CHAR(TO_DATE(DISPLAY_LAST_TRADE_DATE,'YYYY/MM/DD'),'YYYY/MM/DD') END AS LAST_TRADE_DATE
, FOREIGN_BOND_EVALUATE_DATE AS FOREIGN_STANDARD_DATE , SHIKUMI_SAI_KBN AS STRUCTURED_BOND_CLASSIFICATION
, MAX(ACQUIRE_PRICE) AS ACQUIRE_PRICE , MAX(APPRAISE_MARKET_PRICE) AS APPRAISE_MARKET_PRICE , SUM(APPRAISE_PROFIT_LOSS_PRICE) AS APPRAISE_PROFIT_LOSS_PRICE , SUM(EXEC_BASE_BALANCE) AS CONTRACT_STANDARD_DEPOSIT , SUM(CURRENCT_PRICE) AS CURRENT_PRICE , MAX(CURRENCY) AS CURRENCY , SUM(FOREIGN_CURRENCT_PRICE) AS FOREIGN_VALUATION , MAX(EXCHANGE_RATE) AS FX_RATE , CASE MIN(DISPLAY_LAST_TRADE_DATE) WHEN '99991231' THEN '----/--/--' ELSE TO_CHAR(TO_DATE(MIN(DISPLAY_LAST_TRADE_DATE),'YYYY/MM/DD'),'YYYY/MM/DD') END AS LAST_TRADE_DATE
, MIN(FOREIGN_BOND_EVALUATE_DATE) AS FOREIGN_STANDARD_DATE , MIN(SHIKUMI_SAI_KBN) AS STRUCTURED_BOND_CLASSIFICATION
, VISIBLE_BUTEN_CODE AS BUTEN_CODE_VIEW_ABLE FROM ( SELECT VBB.*, SDCR.VISIBLE_BUTEN_CODE FROM ( SELECT VBJ.DATE_YMD AS DATE_YMD , VBJ.BROKER_CODE AS BROKER_CODE , VBJ.BROKER_NAME AS BROKER_NAME , VBJ.DEALER_NUMBER AS DEALER_NUMBER , VBJ.BROKER_BRANCH_CODE AS BROKER_BRANCH_CODE , VBJ.JOINT_BRANCH_CODE AS JOINT_BRANCH_CODE , VBJ.JOINT_BRANCH_NAME AS JOINT_BRANCH_NAME , VBJ.BROKER_CHARGE_CODE AS BROKER_CHARGE_CODE , VBJ.BROKER_CHARGE_NAME AS BROKER_CHARGE_NAME , VBJ.CUSTOMER_ATTRIBUTE AS CUSTOMER_ATTRIBUTE , VBJ.CUSTOMER_ATTRIBUTE_NAME AS CUSTOMER_ATTRIBUTE_NAME , VBJ.BUTEN_CODE AS BUTEN_CODE , VBJ.ACCOUNT_NUMBER AS ACCOUNT_NUMBER , MUAI.NAME_KANJI AS NAME_KANJI , MUAI.NAME_KANA AS NAME_KANA , VBJ.PRODUT_CD AS PRODUT_CD , VBJ.PRODUT_NAME AS PRODUT_NAME , VBJ.BRAND_CODE AS BRAND_CODE , VBJ.BRAND_NAME AS BRAND_NAME , VBJ.TRADE_CD AS TRADE_CD , VBJ.TRADE_NAME AS TRADE_NAME , VBJ.BALANCE_TYPE AS BALANCE_TYPE , VBJ.DEPOSIT_NAME AS DEPOSIT_NAME , VBJ.DEPOSIT_TYPE AS DEPOSIT_TYPE , VBJ.COUNTRY_CODE AS COUNTRY_CODE , VBJ.ACQUIRE_PRICE AS ACQUIRE_PRICE , VBJ.APPRAISE_MARKET_PRICE AS APPRAISE_MARKET_PRICE , VBJ.APPRAISE_PROFIT_LOSS_PRICE AS APPRAISE_PROFIT_LOSS_PRICE , VBJ.EXEC_BASE_BALANCE AS EXEC_BASE_BALANCE , VBJ.CURRENCT_PRICE AS CURRENCT_PRICE , VBJ.CURRENCY AS CURRENCY , VBJ.FOREIGN_CURRENCT_PRICE AS FOREIGN_CURRENCT_PRICE , VBJ.EXCHANGE_RATE AS EXCHANGE_RATE , VBJ.DISPLAY_LAST_TRADE_DATE AS DISPLAY_LAST_TRADE_DATE
, VBJ.FOREIGN_BOND_EVALUATE_DATE AS FOREIGN_BOND_EVALUATE_DATE , ZSFM.SHIKUMI_SAI_KBN AS SHIKUMI_SAI_KBN
FROM V_BALANCE_JOINT VBJ LEFT OUTER JOIN MEDIATE_USER_ATTRIBUTE_INFO MUAI ON VBJ.BUTEN_CODE = MUAI.BUTEN_CODE AND VBJ.ACCOUNT_NUMBER = MUAI.ACCOUNT_NUMBER AND VBJ.BROKER_CODE = MUAI.BROKER_CODE LEFT OUTER JOIN ZERO_STAR_F_MASTER ZSFM ON VBJ.BRAND_CODE = ZSFM.KOYU_CD WHERE 1=1
AND VBJ.BUTEN_CODE = #{req.butenCode}
AND VBJ.ACCOUNT_NUMBER = TO_NUMBER(#{req.accountNumber})
AND VBJ.DATE_YMD between TO_CHAR(TO_DATE(#{req.periodYm}, 'YYYYMM'), 'YYYYMMDD') and TO_CHAR(LAST_DAY(TO_DATE(#{req.periodYm}, 'YYYYMM')), 'YYYYMMDD')
AND LPAD(VBJ.BRAND_CODE,12,'0') = LPAD(#{req.brandCode},12,'0')
AND VBJ.JOINT_BRANCH_CODE = #{req.jointBranchCode}
AND VBJ.JOINT_BRANCH_CODE IN ( SELECT SUB_BROKER_ID FROM TB_MED_USERS WHERE USER_ID = #{req.userId} UNION SELECT SUB_BROKER_ID FROM TB_MED_USERS_PRIV WHERE USER_ID = #{req.userId} AND BROKER_ID = '0509' )
AND VBJ.BROKER_CODE NOT IN
AND VBJ.BROKER_CODE IN
#{item}
AND VBJ.BROKER_CHARGE_CODE = #{req.empCode}
AND ( MUAI.NAME_KANJI = #{req.customerName} OR MUAI.NAME_KANA = #{req.customerName} )
AND ( MUAI.NAME_KANJI LIKE #{req.customerName} || '%' OR MUAI.NAME_KANA LIKE #{req.customerName} || '%' )
AND ( MUAI.NAME_KANJI LIKE '%' || #{req.customerName} || '%' OR MUAI.NAME_KANA LIKE '%' || #{req.customerName} || '%' )
AND VBJ.CUSTOMER_ATTRIBUTE IN
#{item.id}
AND (
VBJ.PRODUT_CD IN
#{item.id}
OR
VBJ.PRODUT_CD IN
#{item.id}
) ) VBB LEFT OUTER JOIN SUB_DEALER_CODE_RELATION_IFAP SDCR ON VBB.ACCOUNT_NUMBER=SDCR.ACCOUNT_NUMBER AND VBB.BUTEN_CODE=SDCR.BUTEN_CODE WHERE 1=1
AND SDCR.VISIBLE_BUTEN_CODE IN
#{item}
) -- 集計
GROUP BY DATE_YMD, BROKER_CODE, BROKER_NAME, DEALER_NUMBER, BROKER_BRANCH_CODE, BROKER_CHARGE_CODE, BROKER_CHARGE_NAME, CUSTOMER_ATTRIBUTE, CUSTOMER_ATTRIBUTE_NAME, BUTEN_CODE, ACCOUNT_NUMBER, NAME_KANJI, NAME_KANA, JOINT_BRANCH_CODE, JOINT_BRANCH_NAME, PRODUT_CD, PRODUT_NAME, BRAND_CODE, BRAND_NAME, TRADE_CD, TRADE_NAME, BALANCE_TYPE, DEPOSIT_NAME, DEPOSIT_TYPE, COUNTRY_CODE, VISIBLE_BUTEN_CODE
ORDER BY BROKER_CODE ASC, BUTEN_CODE ASC, ACCOUNT_NUMBER ASC
ORDER BY BUTEN_CODE ASC, ACCOUNT_NUMBER ASC
) WHERE ROWNUM <= #{req.rownum}
